        .notes-input { width: 100%; max-width: 320px; height: 100px; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); border-radius: 12px; padding: 15px; color: #fff; font-size: 14px; resize: none; margin-bottom: 30px; }
        .notes-input::placeholder { color: rgba(255,255,255,0.3); }
        .save-btn { background: linear-gradient(135deg, #4caf50 0%, #388e3c 100%); color: #fff; padding: 15px 60px; border-radius: 25px; border: none; font-size: 16px; font-weight: 500; cursor: pointer; }
        .overview-card { display: flex; justify-content: space-around; background: linear-gradient(135deg, rgba(74,158,255,0.2) 0%, rgba(53,122,189,0.1) 100%); border-radius: 16px; padding: 20px 10px; margin-bottom: 30px; border: 1px solid rgba(74,158,255,0.2); }
        .overview-item { text-align: center; flex: 1; }
        .overview-number { display: block; font-size: 32px; font-weight: 700; color: #4a9eff; margin-bottom: 4px; }
        .overview-label { font-size: 12px; color: rgba(255,255,255,0.6); }
        .history-list { flex: 1; overflow-y: auto; }
        .history-item { background: rgba(255,255,255,0.05); border-radius: 12px; padding: 15px; margin-bottom: 10px; }
