            </div>
            <div class="main-action">
                <button class="practice-btn" onclick="startPractice()">
                    <span class="btn-text">开始止观</span>
                    <span class="btn-subtext" id="btnSubtext">3分钟 · 引导</span>
                </button>
            </div>
            <div class="selector">
                <span class="selector-label">选择时长</span>
                <div class="options">
                    <div class="option active" onclick="selectDuration(3)"><span class="option-number">3</span><span class="option-unit">分钟</span></div>
