            </div>
            <div class="selector">
                <span class="selector-label">练习模式</span>
                <div class="options">
                    <div class="option active" onclick="selectMode('guided')"><span class="option-number">引导</span><span class="option-unit">适合初学</span></div>
                    <div class="option" onclick="selectMode('silent')"><span class="option-number">自主</span><span class="option-unit">适合熟练</span></div>
                </div>
            </div>
        </div>

        <!-- 练习页面 -->
        <div id="practicePage" class="page practice-page">
            <div class="breath-bg" id="breathBg"></div>
            <div class="practice-header">
                <div class="back-btn" onclick="goBack()">← 返回</div>
