            <div class="timer-section">
                <div class="timer" id="timer">03:00</div>
                <div class="timer-label" id="stageLabel">准备开始</div>
                <div class="audio-controls">
                    <div class="audio-control active" id="audioToggle" onclick="toggleAudio()">🔔 提示音: 开</div>
                    <div class="audio-control" id="bgmToggle" onclick="toggleBGM()">🎵 背景音: 关</div>
                </div>
                <div class="audio-setup" id="audioSetup">
                    <div class="audio-setup-title">音效素材配置</div>
                    <ul class="audio-setup-list">
                        <li>大磬声: assets/large_gong.mp3</li>
                        <li>引磬声: assets/small_bell.mp3</li>
                        <li>木鱼声: assets/wooden_fish.mp3</li>
                        <li>风铃声: assets/wind_chime.mp3</li>
                        <li>水滴声: assets/water_drop.mp3</li>
                    </ul>
                </div>
                <div class="sound-test">
                    <button class="sound-test-btn" onclick="testSound('largeGong')">大磬</button>
                    <button class="sound-test-btn" onclick="testSound('smallBell')">引磬</button>
                    <button class="sound-test-btn" onclick="testSound('woodenFish')">木鱼</button>
                    <button class="sound-test-btn" onclick="testSound('windChime')">风铃</button>
