            </div>
            <div class="controls" id="practiceControls">
                <button class="control-btn start" onclick="startTimer()">开始练习</button>
            </div>
        </div>

        <!-- 完成页面 -->
        <div id="completionPage" class="page completion-page">
            <div class="completion-title">🎉 练习完成</div>
            <div class="completion-time" id="completionTime">实际练习 3 分钟</div>
            <div class="rating-section">
                <span class="rating-label">本次练习质量</span>
                <div class="stars" id="ratingStars">
                    <span class="star" onclick="setRating(1)">★</span><span class="star" onclick="setRating(2)">★</span>
                    <span class="star" onclick="setRating(3)">★</span><span class="star" onclick="setRating(4)">★</span>
                    <span class="star" onclick="setRating(5)">★</span>
                </div>
            </div>
            <textarea class="notes-input" id="practiceNotes" placeholder="记录这次练习的感受（可选）" maxlength="200"></textarea>
            <button class="save-btn" onclick="savePractice()">保存记录</button>
        </div>

        <!-- 统计页面 -->
        <div id="statsPage" class="page stats-page">
            <div class="header"><div class="greeting">修行记录</div><div class="subtitle">见证你的成长</div></div>
            <div class="overview-card">
                <div class="overview-item"><span class="overview-number" id="totalSessions">0</span><span class="overview-label">总次数</span></div>
                <div class="overview-item"><span class="overview-number" id="totalHours">0</span><span class="overview-label">总小时</span></div>
                <div class="overview-item"><span class="overview-number" id="currentStreak">0</span><span class="overview-label">连续天</span></div>
            </div>
            <div class="history-list" id="historyList">
                <div class="empty-state">
                    <div class="empty-icon">🧘</div>
                    <div class="empty-text">还没有练习记录</div>
                    <div class="empty-subtext">开始你的第一次止观练习吧</div>
                </div>
            </div>
        </div>

        <!-- 底部导航 -->
        <div class="tab-bar">
            <div class="tab-item active" onclick="showPage('home')" id="tabHome"><div class="tab-icon">🧘</div><div class="tab-text">练习</div></div>
            <div class="tab-item" onclick="showPage('stats')" id="tabStats"><div class="tab-icon">📊</div><div class="tab-text">记录</div></div>
        </div>
    </div>

    <script>
        // ============ 音效素材配置 ============
        const AUDIO_ASSETS = {
            largeGong: './assets/large_gong.mp3',
            smallBell: './assets/small_bell.mp3',
            woodenFish: './assets/wooden_fish.mp3',
            windChime: './assets/wind_chime.mp3',
            waterDrop: './assets/water_drop.mp3',
            useSynthetic: true  // 设为 false 当真实音效文件准备好后
        };

        // 20分钟完整版时间点配置
        const AUDIO_CUES_20MIN = [
            { time: 0, sound: 'largeGong', volume: 0.8, label: '开场' },
            { time: 30, sound: 'waterDrop', volume: 0.3, label: '调身开始' },
            { time: 120, sound: 'smallBell', volume: 0.5, label: '入止' },
            { time: 600, sound: 'windChime', volume: 0.4, label: '止中过渡' },
            { time: 900, sound: 'windChime', volume: 0.4, label: '观心过渡' },
            { time: 1080, sound: 'woodenFish', volume: 0.5, label: '回向' },
            { time: 1170, sound: 'smallBell', volume: 0.5, label: '准备收功' },
            { time: 1200, sound: 'largeGong', volume: 0.8, label: '结束' }
        ];

        // 数据存储
        let settings = { duration: 3, mode: 'guided' };
        let practiceHistory = JSON.parse(localStorage.getItem('zhiguan_history') || '[]');
        let currentPractice = { startTime: null, duration: 3, mode: 'guided', rating: 0, notes: '' };
        let timer = null, remainingTime = 180, totalTime = 180, isPlaying = false;
        let audioContext = null, audioEnabled = true, bgmEnabled = false;
        let audioVolume = 0.5, playedCues = new Set(), audioElements = {};

        // ============ 音频系统 ============
        function initAudio() {
            try {
                audioContext = new (window.AudioContext || window.webkitAudioContext)();
                preloadAudioAssets();
            } catch (e) { audioEnabled = false; }
        }

        function preloadAudioAssets() {
            if (AUDIO_ASSETS.useSynthetic) return;
            ['largeGong', 'smallBell', 'woodenFish', 'windChime', 'waterDrop'].forEach(sound => {
                const audio = new Audio(AUDIO_ASSETS[sound]);
                audio.preload = 'auto';
                audioElements[sound] = audio;
            });
        }

        function playSound(soundType, volume = 0.5) {
            if (!audioEnabled) return;
            if (!AUDIO_ASSETS.useSynthetic && audioElements[soundType]) {
                const audio = audioElements[soundType].cloneNode();
                audio.volume = volume;
                audio.play().catch(e => playSyntheticSound(soundType, volume));
            } else {
                playSyntheticSound(soundType, volume);
            }
        }

        function playSyntheticSound(soundType, volume = 0.5) {
            if (!audioContext) return;
            switch(soundType) {
                case 'largeGong': playBellSound(180, 3, volume); break;
                case 'smallBell': playBellSound(880, 1.5, volume); break;
                case 'woodenFish': playWoodBlockSound(volume); break;
                case 'windChime': playChimeSound(volume); break;
                case 'waterDrop': playWaterDropSound(volume); break;
            }
        }

        function playBellSound(frequency, duration, volume) {
            const oscillator = audioContext.createOscillator();
            const gainNode = audioContext.createGain();
            oscillator.connect(gainNode);
            gainNode.connect(audioContext.destination);
            oscillator.frequency.value = frequency;
            oscillator.type = 'sine';
            const now = audioContext.currentTime;
            gainNode.gain.setValueAtTime(0, now);
            gainNode.gain.linearRampToValueAtTime(volume * 0.5, now + 0.05);
            gainNode.gain.exponentialRampToValueAtTime(volume * 0.1, now + duration * 0.3);
            gainNode.gain.exponentialRampToValueAtTime(0.001, now + duration);
            oscillator.start(now);
            oscillator.stop(now + duration);
            addHarmonics(frequency, duration, volume * 0.3);
        }

        function addHarmonics(baseFreq, duration, volume) {
            [2, 3, 4].forEach((harmonic, i) => {
                setTimeout(() => {
                    const osc = audioContext.createOscillator();
                    const gain = audioContext.createGain();
                    osc.connect(gain);
                    gain.connect(audioContext.destination);
                    osc.frequency.value = baseFreq * harmonic;
                    osc.type = 'sine';
                    const now = audioContext.currentTime;
                    gain.gain.setValueAtTime(0, now);
                    gain.gain.linearRampToValueAtTime(volume * 0.2, now + 0.02);
                    gain.gain.exponentialRampToValueAtTime(0.001, now + duration * 0.5);
                    osc.start(now);
                    osc.stop(now + duration * 0.5);
                }, i * 50);
            });
        }

        function playWoodBlockSound(volume) {
            const oscillator = audioContext.createOscillator();
            const gainNode = audioContext.createGain();
            oscillator.connect(gainNode);
            gainNode.connect(audioContext.destination);
            oscillator.frequency.setValueAtTime(800, audioContext.currentTime);
            oscillator.frequency.exponentialRampToValueAtTime(400, audioContext.currentTime + 0.1);
            oscillator.type = 'triangle';
            const now = audioContext.currentTime;
            gainNode.gain.setValueAtTime(0, now);
            gainNode.gain.linearRampToValueAtTime(volume * 0.6, now + 0.01);
            gainNode.gain.exponentialRampToValueAtTime(0.001, now + 0.15);
            oscillator.start(now);
            oscillator.stop(now + 0.15);
        }

        function playChimeSound(volume) {
            const frequencies = [523, 659, 784, 1047];
            frequencies.forEach((freq, i) => {
                setTimeout(() => {
                    const osc = audioContext.createOscillator();
                    const gain = audioContext.createGain();
                    osc.connect(gain);
                    gain.connect(audioContext.destination);
                    osc.frequency.value = freq;
                    osc.type = 'sine';
                    const now = audioContext.currentTime;
                    gain.gain.setValueAtTime(0, now);
                    gain.gain.linearRampToValueAtTime(volume * 0.15, now + 0.02);
                    gain.gain.exponentialRampToValueAtTime(0.001, now + 1.5);
                    osc.start(now);
                    osc.stop(now + 1.5);
                }, i * 80);
            });
        }

        function playWaterDropSound(volume) {
            const oscillator = audioContext.createOscillator();
            const gainNode = audioContext.createGain();
            oscillator.connect(gainNode);
            gainNode.connect(audioContext.destination);
            oscillator.frequency.setValueAtTime(1200, audioContext.currentTime);
            oscillator.frequency.exponentialRampToValueAtTime(600, audioContext.currentTime + 0.15);
            oscillator.type = 'sine';
            const now = audioContext.currentTime;
            gainNode.gain.setValueAtTime(0, now);
            gainNode.gain.linearRampToValueAtTime(volume * 0.3, now + 0.01);
            gainNode.gain.exponentialRampToValueAtTime(0.001, now + 0.2);
            oscillator.start(now);
            oscillator.stop(now + 0.2);
        }

        function testSound(soundType) {
            if (audioContext && audioContext.state === 'suspended') audioContext.resume();
            playSound(soundType, 0.6);
        }

        function playStageSound(stage) {
            if (!audioEnabled) return;
            const stageSounds = { 'start': 'largeGong', 'tiaoshen': 'waterDrop', 'tiaoxi': 'smallBell', 'guanxin': 'windChime', 'shougong': 'woodenFish', 'end': 'largeGong' };
            if (stageSounds[stage]) playSound(stageSounds[stage], 0.5);
        }

        function checkAudioCues(elapsedSeconds) {
            if (!audioEnabled || settings.duration !== 20) return;
            AUDIO_CUES_20MIN.forEach(cue => {
                if (elapsedSeconds >= cue.time && !playedCues.has(cue.time)) {
                    playedCues.add(cue.time);
                    playSound(cue.sound, cue.volume);
                }
            });
        }

        function toggleAudio() {
            audioEnabled = !audioEnabled;
            const control = document.getElementById('audioToggle');
            control.textContent = audioEnabled ? '🔔 提示音: 开' : '🔕 提示音: 关';
            control.classList.toggle('active', audioEnabled);
        }

        function toggleBGM() {
            bgmEnabled = !bgmEnabled;
            const control = document.getElementById('bgmToggle');
            control.textContent = bgmEnabled ? '🎵 背景音: 开' : '🔇 背景音: 关';
            control.classList.toggle('active', bgmEnabled);
        }
