## 【第三段：JS练习逻辑 + 页面控制】

```javascript
        // ============ 页面控制 ============
        function setGreeting() {
            const hour = new Date().getHours();
            let greeting = '你好';
            if (hour < 6) greeting = '夜深了';
            else if (hour < 9) greeting = '早安';
            else if (hour < 12) greeting = '上午好';
            else if (hour < 14) greeting = '午安';
            else if (hour < 18) greeting = '下午好';
            else greeting = '晚上好';
            document.getElementById('greeting').textContent = greeting;
        }

        function selectDuration(duration) {
            settings.duration = duration;
            document.querySelectorAll('.selector:first-of-type .option').forEach((el, i) => {
                el.classList.toggle('active', [3, 5, 10, 20][i] === duration);
            });
            updateBtnSubtext();
        }

        function selectMode(mode) {
            settings.mode = mode;
            document.querySelectorAll('.selector:last-of-type .option').forEach((el, i) => {
                el.classList.toggle('active', ['guided', 'silent'][i] === mode);
            });
            updateBtnSubtext();
        }

        function updateBtnSubtext() {
            const modeText = settings.mode === 'guided' ? '引导' : '自主';
            document.getElementById('btnSubtext').textContent = `${settings.duration}分钟 · ${modeText}`;
        }

        function startPractice() {
            currentPractice.duration = settings.duration;
            currentPractice.mode = settings.mode;
            remainingTime = settings.duration * 60;
            totalTime = remainingTime;
            playedCues.clear();
            document.getElementById('practiceDuration').textContent = `${settings.duration}分钟止观`;
            document.getElementById('practiceMode').textContent = settings.mode === 'guided' ? '引导练习' : '自主练习';
            document.getElementById('timer').textContent = formatTime(remainingTime);
            document.getElementById('guideText').style.display = settings.mode === 'guided' ? 'block' : 'none';
            document.getElementById('audioSetup').style.display = settings.duration === 20 ? 'block' : 'none';
            showPage('practice');
        }

        function formatTime(seconds) {
            const mins = Math.floor(seconds / 60);
            const secs = seconds % 60;
            return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
        }

        function startTimer() {
            if (audioContext && audioContext.state === 'suspended') audioContext.resume();
            isPlaying = true;
            currentPractice.startTime = new Date();
            playStageSound('start');
            document.getElementById('breathBg').classList.add('breathing');
            document.getElementById('practiceControls').innerHTML = `
                <button class="control-btn pause" onclick="pauseTimer()">暂停</button>
                <button class="control-btn end" onclick="endPractice()">结束</button>
            `;
            let lastStage = '';
            timer = setInterval(() => {
                remainingTime--;
                const elapsed = totalTime - remainingTime;
                document.getElementById('timer').textContent = formatTime(remainingTime);
                const progress = (elapsed / totalTime) * 100;
                document.getElementById('progressFill').style.width = `${progress}%`;
                document.getElementById('progressText').textContent = `${Math.floor(progress)}%`;
                const currentStage = updateStageLabel();
                updateGuideText();
                if (currentStage !== lastStage && lastStage !== '') playStageSound(currentStage);
                lastStage = currentStage;
                checkAudioCues(elapsed);
                if (remainingTime <= 0) endPractice();
            }, 1000);
        }

        function pauseTimer() {
            isPlaying = false;
            clearInterval(timer);
            document.getElementById('breathBg').classList.remove('breathing');
            document.getElementById('practiceControls').innerHTML = `
                <button class="control-btn start" onclick="resumeTimer()">继续</button>
                <button class="control-btn end" onclick="endPractice()">结束</button>
            `;
        }

        function resumeTimer() { startTimer(); }

        function updateStageLabel() {
            const elapsed = totalTime - remainingTime;
            const progress = elapsed / totalTime;
            let label = '准备开始', stageKey = '';
            if (progress > 0) {
                if (progress < 0.17) { label = '调身'; stageKey = 'tiaoshen'; }
                else if (progress < 0.67) { label = '调息'; stageKey = 'tiaoxi'; }
                else if (progress < 0.89) { label = '观心'; stageKey = 'guanxin'; }
                else { label = '收功'; stageKey = 'shougong'; }
            }
            document.getElementById('stageLabel').textContent = label;
            return stageKey;
        }

        function updateGuideText() {
            if (currentPractice.mode !== 'guided') return;
            const elapsed = totalTime - remainingTime;
            const progress = elapsed / totalTime;
            let text = '';
            if (progress < 0.17) text = '让身体自然放松，脊柱轻轻挺直';
            else if (progress < 0.67) text = '吸气...呼气...保持自然的呼吸节奏';
            else if (progress < 0.89) text = '觉察身体的感觉，不评判，只是知道';
            else text = '慢慢把觉知带回，准备结束练习';
            document.getElementById('guideText').textContent = text;
        }

        function endPractice() {
            clearInterval(timer);
            isPlaying = false;
            playStageSound('end');
            const actualDuration = Math.floor((new Date() - currentPractice.startTime) / 1000 / 60);
            document.getElementById('completionTime').textContent = `实际练习 ${actualDuration < 1 ? 1 : actualDuration} 分钟`;
            showPage('completion');
        }

        function goBack() {
            if (isPlaying) {
                if (confirm('练习正在进行中，确定要退出吗？')) {
                    clearInterval(timer);
                    showPage('home');
                }
            } else {
                showPage('home');
            }
        }

        function setRating(rating) {
            currentPractice.rating = rating;
            document.querySelectorAll('#ratingStars .star').forEach((el, i) => {
                el.classList.toggle('active', i < rating);
            });
        }

        function savePractice() {
            currentPractice.notes = document.getElementById('practiceNotes').value;
            const record = {
                id: Date.now(),
                date: new Date().toISOString(),
                duration: currentPractice.duration,
                mode: currentPractice.mode,
                rating: currentPractice.rating,
                notes: currentPractice.notes
            };
            practiceHistory.unshift(record);
            localStorage.setItem('zhiguan_history', JSON.stringify(practiceHistory));
            currentPractice.rating = 0;
            currentPractice.notes = '';
            document.getElementById('practiceNotes').value = '';
            document.querySelectorAll('#ratingStars .star').forEach(el => el.classList.remove('active'));
            updateHomeStats();
            updateStatsPage();
            showPage('stats');
        }

        function updateHomeStats() {
            const today = new Date().toDateString();
            const todayCount = practiceHistory.filter(r => new Date(r.date).toDateString() === today).length;
            const streak = calculateStreak();
            const totalMinutes = Math.floor(practiceHistory.reduce((sum, r) => sum + r.duration, 0));
            document.getElementById('todayCount').textContent = todayCount;
            document.getElementById('streak').textContent = streak;
            document.getElementById('totalMinutes').textContent = totalMinutes;
        }

        function calculateStreak() {
            if (practiceHistory.length === 0) return 0;
            const dates = [...new Set(practiceHistory.map(r => new Date(r.date).toDateString()))]
                .sort((a, b) => new Date(b) - new Date(a));
            let streak = 0;
            const today = new Date().toDateString();
            const yesterday = new Date(Date.now() - 86400000).toDateString();
            if (dates[0] === today || dates[0] === yesterday) {
                streak = 1;
                for (let i = 1; i < dates.length; i++) {
                    const prev = new Date(dates[i - 1]);
                    const curr = new Date(dates[i]);
                    if ((prev - curr) / 86400000 === 1) streak++;
                    else break;
                }
            }
            return streak;
        }

        function updateStatsPage() {
            const totalSessions = practiceHistory.length;
            const totalHours = Math.floor(practiceHistory.reduce((sum, r) => sum + r.duration, 0) / 60 * 10) / 10;
            const streak = calculateStreak();
            document.getElementById('totalSessions').textContent = totalSessions;
            document.getElementById('totalHours').textContent = totalHours;
            document.getElementById('currentStreak').textContent = streak;
            const historyList = document.getElementById('historyList');
            if (practiceHistory.length === 0) {
                historyList.innerHTML = `
                    <div class="empty-state">
                        <div class="empty-icon">🧘</div>
                        <div class="empty-text">还没有练习记录</div>
                        <div class="empty-subtext">开始你的第一次止观练习吧</div>
                    </div>`;
                return;
            }
            historyList.innerHTML = practiceHistory.slice(0, 20).map(record => {
                const date = new Date(record.date);
                const stars = '★'.repeat(record.rating || 0) + '☆'.repeat(5 - (record.rating || 0));
                return `
                    <div class="history-item">
                        <div class="history-main">
                            <div class="history-date">
                                <div class="date-day">${date.getDate()}</div>
                                <div class="date-month">${date.getMonth() + 1}月</div>
                            </div>
                            <div class="history-info">
                                <div class="history-duration">${record.duration}分钟止观</div>
                                <div class="history-mode">${record.mode === 'guided' ? '引导练习' : '自主练习'}</div>
                            </div>
                            <div class="history-rating">${stars}</div>
                        </div>
                        ${record.notes ? `<div class="history-notes">${record.notes}</div>` : ''}
                    </div>`;
            }).join('');
        }

        function showPage(page) {
            document.querySelectorAll('.page').forEach(el => el.classList.remove('active'));
            document.querySelectorAll('.tab-item').forEach(el => el.classList.remove('active'));
            if (page === 'home') {
                document.getElementById('homePage').classList.add('active');
                document.getElementById('tabHome').classList.add('active');
                updateHomeStats();
            } else if (page === 'practice') {
                document.getElementById('practicePage').classList.add('active');
            } else if (page === 'completion') {
                document.getElementById('completionPage').classList.add('active');
            } else if (page === 'stats') {
                document.getElementById('statsPage').classList.add('active');
                document.getElementById('tabStats').classList.add('active');
                updateStatsPage();
            }
        }

        // 初始化
        document.addEventListener('DOMContentLoaded', () => {
            setGreeting();
            updateHomeStats();
            updateStatsPage();
            initAudio();
        });
    </script>
</body>
</html>
```

