    remainingTime: 180,
    isPlaying: false,
    isPaused: false,
    audioEnabled: true,
    stageLabel: '准备开始',
    guideText: '点击开始，进入止观练习',
    formattedTime: '03:00',
    currentPhase: 'prepare'  // prepare, stop, observe, finish
  },

  timer: null,
  startTime: null,
  playedCues: new Set(),
  waterDropTimer: null,
  windChimeTimer: null,

  onLoad(options) {
    const systemInfo = wx.getSystemInfoSync()
    const duration = parseInt(options.duration) || 3
    const mode = options.mode || 'guided'

    this.setData({
      statusBarHeight: systemInfo.statusBarHeight,
      duration,
      mode,
      remainingTime: duration * 60,
      formattedTime: this.formatTime(duration * 60),
      audioEnabled: app.globalData.settings.audioEnabled
    })
  },

  onUnload() {
    this.clearAllTimers()
  },

  // 格式化时间
  formatTime(seconds) {
    const mins = Math.floor(seconds / 60)
    const secs = seconds % 60
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`
  },

  // 播放音效
  playSound(soundName, volume = 0.6) {
    if (!this.data.audioEnabled) return

    const src = SOUND_MAP[soundName]
    if (!src) return

    const innerAudioContext = wx.createInnerAudioContext()
    innerAudioContext.src = src
    innerAudioContext.volume = volume
    innerAudioContext.play()

    innerAudioContext.onEnded(() => innerAudioContext.destroy())
    innerAudioContext.onError(() => innerAudioContext.destroy())
  },

  // 开始练习
  startTimer() {
    this.setData({ isPlaying: true, isPaused: false })
    this.startTime = new Date()
    this.playedCues.clear()

    const totalSeconds = this.data.duration * 60

    // 播放开场大磬（低音量，顺滑）
    if (this.data.audioEnabled) {
      this.playSound('largeGong', 0.5)
      wx.vibrateLong()
    }

    // 主计时器
    this.timer = setInterval(() => {
      const remaining = this.data.remainingTime - 1
      this.setData({
        remainingTime: remaining,
        formattedTime: this.formatTime(remaining)
      })

      // 检查各阶段
      this.checkPhases(totalSeconds, remaining)

      // 结束
      if (remaining <= 0) {
        this.completePractice()
      }
    }, 1000)
  },

  // 检查各阶段
  checkPhases(total, remaining) {
    const elapsed = total - remaining

    // 0-15秒：开场调身调息调心（大磬已播放）
    if (elapsed >= 0 && elapsed < 15) {
      if (!this.playedCues.has('prepare')) {
        this.playedCues.add('prepare')
        this.setData({
          stageLabel: '调身调息',
          guideText: '调整坐姿，自然呼吸，让心安定',
          currentPhase: 'prepare'
        })
      }
    }

    // 16秒：进入止息，开始水滴声
    if (elapsed >= 16 && !this.playedCues.has('stop_start')) {
      this.playedCues.add('stop_start')
      this.setData({
        stageLabel: '止息',
        guideText: '保持觉知，安住于止',
        currentPhase: 'stop'
      })
      this.startWaterDrop()
    }

    // 1分30秒（90秒）：转入观心，风铃声
    if (elapsed >= 90 && !this.playedCues.has('observe_start')) {
      this.playedCues.add('observe_start')
      this.stopWaterDrop()
      this.setData({
        stageLabel: '观心',
        guideText: '觉察心念，不随不拒',
        currentPhase: 'observe'
      })
      this.playSound('windChime', 0.5)
      this.startWindChime()
    }

    // 最后15秒：木鱼准备收功
    if (remaining <= 15 && remaining > 5 && !this.playedCues.has('prepare_end')) {
      this.playedCues.add('prepare_end')
      this.stopWindChime()
      this.setData({
        stageLabel: '准备收功',
        guideText: '慢慢把觉知带回',
        currentPhase: 'finish'
      })
      this.playSound('woodenFish', 0.6)
      wx.vibrateShort({ type: 'medium' })
    }
  },

  // 水滴声循环（每3-5秒一次）
  startWaterDrop() {
    // 立即播放一次
    this.playSound('waterDrop', 0.4)

    // 循环播放
    const playLoop = () => {
      if (this.data.currentPhase !== 'stop') return

      this.playSound('waterDrop', 0.4)

      // 随机间隔3-5秒
      const interval = 3000 + Math.random() * 2000
      this.waterDropTimer = setTimeout(playLoop, interval)
    }

    this.waterDropTimer = setTimeout(playLoop, 4000)
  },

  stopWaterDrop() {
    if (this.waterDropTimer) {
      clearTimeout(this.waterDropTimer)
      this.waterDropTimer = null
    }
  },

  // 风铃声循环（3秒一次，间隔10-8秒递减）
  startWindChime() {
    let interval = 10000  // 初始10秒

    const playLoop = () => {
      if (this.data.currentPhase !== 'observe') return

      this.playSound('windChime', 0.5)

      // 间隔递减（10秒 -> 8秒）
      interval = Math.max(8000, interval - 500)
      this.windChimeTimer = setTimeout(playLoop, interval)
    }

    // 3秒后第一次播放
    this.windChimeTimer = setTimeout(playLoop, 3000)
  },

  stopWindChime() {
    if (this.windChimeTimer) {
      clearTimeout(this.windChimeTimer)
      this.windChimeTimer = null
    }
  },

  // 暂停
  pauseTimer() {
    this.clearAllTimers()
    this.setData({ isPlaying: false, isPaused: true })
  },

  // 继续
  resumeTimer() {
    this.startTimer()
  },

  // 结束练习
  endPractice() {
    this.clearAllTimers()

    wx.showModal({
      title: '结束练习',
      content: '确定要结束当前练习吗？',
      confirmText: '结束',
      cancelText: '继续',
      success: (res) => {
        if (res.confirm) {
          this.saveAndExit()
        } else {
          this.resumeTimer()
        }
      }
    })
  },

  // 完成练习
  completePractice() {
    this.clearAllTimers()

    // 播放引磬结束（3-5秒）
    if (this.data.audioEnabled) {
      this.playSound('smallBell', 0.6)
      wx.vibrateLong()
    }

    this.saveAndExit(true)
  },

  // 保存并跳转到评分页
  saveAndExit(completed = false) {
    const actualDuration = this.startTime 
      ? Math.floor((new Date() - this.startTime) / 1000 / 60)
      : 0

    const record = {
      id: Date.now(),
      date: new Date().toISOString(),
      duration: this.data.duration,
      mode: this.data.mode,
      completed,
      actualDuration: actualDuration < 1 ? 1 : actualDuration
    }

    const records = wx.getStorageSync('zhiguan_records') || []
    records.unshift(record)
    wx.setStorageSync('zhiguan_records', records)

    // 跳转到评分页
    wx.redirectTo({
      url: `/pages/feedback/feedback?recordId=${record.id}&duration=${this.data.duration}&completed=${completed}`
    })
  },

  // 清除所有定时器
  clearAllTimers() {
    if (this.timer) {
      clearInterval(this.timer)
      this.timer = null
    }
    this.stopWaterDrop()
    this.stopWindChime()
  },

  // 切换音频
  toggleAudio() {
    const audioEnabled = !this.data.audioEnabled
    this.setData({ audioEnabled })
    app.globalData.settings.audioEnabled = audioEnabled
    wx.setStorageSync('zhiguan_settings', app.globalData.settings)
  },

  // 返回
  goBack() {
    if (this.data.isPlaying) {
      this.pauseTimer()
      wx.showModal({
        title: '退出练习',
        content: '练习正在进行中，确定要退出吗？',
        success: (res) => {
          if (res.confirm) {
            this.clearAllTimers()
            wx.navigateBack()
          } else {
            this.resumeTimer()
          }
        }
      })
    } else {
      wx.navigateBack()
    }
  }
})

/**pages/index/index.js**/
const app = getApp()

Page({
  data: {
    statusBarHeight: 44,
    greeting: '你好',
    todayCount: 0,
    streak: 0,
    duration: 3,
    mode: 'guided',
    breathing: true
  },

  onLoad() {
    // 获取状态栏高度
    const systemInfo = wx.getSystemInfoSync()
    this.setData({
      statusBarHeight: systemInfo.statusBarHeight
    })

    // 设置问候语
    this.setGreeting()

    // 加载设置
    this.loadSettings()

    // 加载统计数据
    this.loadStats()
  },

  onShow() {
    this.loadStats()
  },

  // 设置问候语
  setGreeting() {
    const hour = new Date().getHours()
    let greeting = '你好'
    if (hour < 6) greeting = '夜深了'
    else if (hour < 9) greeting = '早安'
    else if (hour < 12) greeting = '上午好'
    else if (hour < 14) greeting = '午安'
    else if (hour < 18) greeting = '下午好'
    else greeting = '晚上好'

    this.setData({ greeting })
  },

  // 加载设置
  loadSettings() {
    const settings = app.globalData.settings
    this.setData({
      duration: settings.duration,
      mode: settings.mode
    })
  },

  // 加载统计数据
  loadStats() {
    const records = wx.getStorageSync('zhiguan_records') || []

    // 今日练习次数
    const today = new Date().toDateString()
    const todayCount = records.filter(r => new Date(r.date).toDateString() === today).length

    // 连续天数
    const streak = this.calculateStreak(records)

    this.setData({ todayCount, streak })
  },

  // 计算连续天数
  calculateStreak(records) {
    if (records.length === 0) return 0

    const dates = [...new Set(records.map(r => new Date(r.date).toDateString()))]
      .sort((a, b) => new Date(b) - new Date(a))

    let streak = 0
    const today = new Date().toDateString()
    const yesterday = new Date(Date.now() - 86400000).toDateString()

    if (dates[0] === today || dates[0] === yesterday) {
      streak = 1
      for (let i = 1; i < dates.length; i++) {
        const prev = new Date(dates[i - 1])
        const curr = new Date(dates[i])
        if ((prev - curr) / 86400000 === 1) {
          streak++
        } else {
          break
        }
      }
    }

    return streak
  },

  // 选择时长 - 只保留3/5/15分钟
  selectDuration(e) {
    const duration = parseInt(e.currentTarget.dataset.duration)
    this.setData({ duration })

    // 保存设置
    app.globalData.settings.duration = duration
    wx.setStorageSync('zhiguan_settings', app.globalData.settings)

    // 震动反馈
    wx.vibrateShort({ type: 'light' })
  },

  // 选择模式
  selectMode(e) {
    const mode = e.currentTarget.dataset.mode
    this.setData({ mode })

    // 保存设置
    app.globalData.settings.mode = mode
    wx.setStorageSync('zhiguan_settings', app.globalData.settings)
  },

  // 开始练习
  startPractice() {
    wx.vibrateShort({ type: 'medium' })

    wx.navigateTo({
      url: `/pages/practice/practice?duration=${this.data.duration}&mode=${this.data.mode}`
    })
  }
})

